<template>
  <div>
    <form>
      <table
        width="98%"
        border="0"
        align="center"
        cellpadding="0"
        cellspacing="0"
        @click="executeOpenFile()"
      >
        <tr>
          <td bgcolor="#0A7E81">
            <table width="100%" border="0" cellpadding="0" cellspacing="0">
              <tr>
                <td width="26%" height="60" align="right">
                  <img :src="requireImg('images/file.png')" width="40" height="52" />
                </td>
                <td width="74%">
                  <span class="STYLE1">　请选择要上传的文件</span>
                </td>
              </tr>
            </table>
          </td>
        </tr>
      </table>

      <br />

      <table
        width="98%"
        border="0"
        align="center"
        cellpadding="0"
        cellspacing="0"
      >
        <tr>
          <td width="50">
            <table width="100%" border="0" cellspacing="0" cellpadding="0">
              <tr>
                <td width="30">
                  <table width="30" border="0" cellspacing="0" cellpadding="0">
                    <tr>
                      <td
                        height="30"
                        align="center"
                        background="images/round.png"
                      >
                        <span class="STYLE2">1</span>
                      </td>
                    </tr>
                  </table>
                </td>

                <td width="20">&nbsp;</td>
              </tr>
            </table>
          </td>
          <td width="77%">
            <label>
              <input
                name="file"
                type="text"
                class="bk"
                id="file"
                size="30"
                readonly="true"
              />
            </label>
          </td>
          <td width="15%">
            <img
              :src="requireImg('images/X.png')"
              width="30"
              height="30"
              @click="executeClear()"
            />
          </td>
        </tr>
      </table>

      <!--状态div-->

      <div id="a" class="a"><div id="b" class="b"></div></div>
      <div
        id="pre"
        name="pre"
        style="
          color: #000000;
          height: 50px;
          width: 100%;
          text-align: center;
          font-size: 15px;
          font-weight: bold;
        "
      ></div>

      <!--文件下载 start-->

      <div
        id="fileDown"
        name="pre"
        style="
          color: #000000;
          height: 50px;
          width: 100%;
          text-align: center;
          font-size: 15px;
          font-weight: bold;
        "
      ></div>
      <!--文件下载 end-->

      <div
        id="isok"
        name="isok"
        style="
          color: #aabb00;
          height: 100px;
          width: 100%;
          text-align: center;
          line-height: 200px;
          font-size: 32px;
          font-weight: bold;
        "
      ></div>
      <br />
      <br />

      <table
        width="100%"
        border="0"
        align="center"
        cellpadding="0"
        cellspacing="0"
        style="position: absolute; bottom: 0px"
        @click="startupload()"
      >
        <tr>
          <td bgcolor="#0A7E81">
            <table width="100%" border="0" cellpadding="0" cellspacing="0">
              <tr>
                <td width="50%" align="right">
                  <img :src="requireImg('images/find.png')" width="72" height="50" />
                </td>
                <td width="50%" id="contron">
                  <span class="STYLE1">开始</span>
                </td>
              </tr>
            </table>
          </td>
        </tr>
      </table>
      <div style="opacity: 0"></div>
    </form>
    <p>&nbsp;</p>
  </div>
</template>

<script>
export default {
  name: "filebreakpointTransferList", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      isUploading: false,
      timer: null,
      isstart: false,
    };
  },
  computed: {},
  created() {},
  mounted() {
    this.init();
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //更新进度
    loading(v) {
      document.getElementById("b").style.width = v * 2 + "px";
      document.getElementById("pre").innerHTML = v + "%";
    },

    resetloading() {
      document.getElementById("b").style.width = 0 * 2 + "px";
      document.getElementById("pre").innerHTML = 0 + "%";
    },

    //初始化读取文件信息
    init() {
      //取数据
      var data = {
        bic: "getFile",
      };
      mam.navigator.ajax.getJSON(
        "appcode_SYS13",
        data,
        "getJSON",
        this.successCallback
      );

      //$.ajax( {
      //	type : "post",
      //	url : "getFile.action",
      //	success : function(d) {
      //	var ret = eval("(" + d + ")");//JSON.parse(d);
      //	var ret1 = ret._ajax_op_flag;
      //	var filevalue = "";
      //	alert(ret1);
      //	if (ret1 == "success") {
      //		$.each(ret.fileName, function(i, v) {
      //			//				alert(v);
      //				filevalue += "<a href='download.action?fileName="+v+"'>" + v
      //						+ "</br>";
      //
      //			})
      //		$("#fileDown").html(filevalue);

      //			}

      //		},
      //		error : function() {
      //			alert("数据异常!");
      //		}
      //		});
    },
    successCallback(v) {
      alert("successCallback");
      var json = JSON.stringify(v);
      alert("getJson插件调用成功: " + json);
    },

    //执行发送文件操作
    executeSend() {
      var filePath = "";
      //filePath = "/sdcard/zhouxuesong/reader.txt";
      //filePath = "/sdcard/zhouxuesong/ibm_driver_install.zip";
      filePath = document.getElementById("file").value;
      console.log("executeSend()--filePath:" + filePath);
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }

      //满足条件表示正在执行上传，如果在上传过程中时用户还在点击上传，则不进行上传操作
      //下面代码是避免多次点击上传多个文件
      if (this.isUploading) {
        console.log("executeSend() is uploading,return");
        return;
      }

      if (filePath == "") {
        document.getElementById("isok").innerHTML = "请选择要上传的文件";
        return;
      }
      this.isUploading = true;
      document.getElementById("isok").innerHTML = "正在上传...";
      this.timer = setInterval(progress, 200);
      filePath = document.getElementById("file").value;
      //navigator.dlfilebreakpointtransfer.fileUpload(successCallback,errorCallback,filePath);
      alert("建设中,此处仅做参考");
      mam.navigator.appupload.appServerUpload(
        successCallback,
        errorCallback,
        "appcode_SYS13",
        "upload",
        filePath,
        ""
      );
      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        clearInterval(this.timer);
        this.isstart = false;
        document.getElementById("contron").innerHTML = "开始";
        if (msg == 100) {
          document.getElementById("isok").innerHTML = "服务器已存在此文件";
        } else {
          document.getElementById("isok").innerHTML = "文件上传成功";
        }
        console.log("successCallback() msg:" + msg);
        this.isUploading = false;
        this.showOrHideIsUploadingMsg();
      }

      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(dlFileTransferError) {
        //var errorCode = dlFileTransferError.code;
        //返回错误码对象
        clearInterval(this.timer);
        this.isstart = false;
        document.getElementById("contron").innerHTML = "开始";
        this.resetloading();
        if (dlFileTransferError.code == 6) {
          document.getElementById("isok").innerHTML = "暂停成功";
        } else if (dlFileTransferError.code == 1) {
          document.getElementById("isok").innerHTML = "文件不存在";
        } else {
          document.getElementById("isok").innerHTML = "文件上传失败";
        }
        this.isUploading = false;
        this.showOrHideIsUploadingMsg();
        //console.log("errorCallback()dlFileTransferError.code :" + errorCode);
      }
    },

    startupload() {
      if (this.isstart) {
        document.getElementById("contron").innerHTML = "开始";
        mam.navigator.dlfilebreakpointtransfer.pause(successCallback, null);

        function successCallback(msg) {}

        function errorCallback(msg) {}
        this.isstart = false;
      } else {
        this.executeSend();
        document.getElementById("contron").innerHTML = "暂停";
        this.isstart = true;
      }
    },

    progress() {
      mam.navigator.dlfilebreakpointtransfer.progress(successCallback, null);

      function successCallback(msg) {
        this.loading(msg);
      }

      function errorCallback(msg) {}
    },

    executeClear() {
      if (!this.isUploading) {
        document.getElementById("file").value = "";
        document.getElementById("isok").innerHTML = "";
      } else {
        //不执行任何操作
      }
      //内部有isUploading判断，不受上面if/else影响
      this.showOrHideIsUploadingMsg();
    },

    //如果用户正在执行上传，此时点击清除按钮时显示的消息
    showOrHideIsUploadingMsg() {
      //全局变量，标识当前状态，当前为文件正在上传状态
      if (this.isUploading) {
        //如果当前正在上传状态，并且此对象没显示，设定此对象为显示状态
        if ("none" == document.getElementById("error").style.display) {
          document.getElementById("error").style.display = "block";
        }
      } else {
        //当前为不在上传状态，并且此对象设定为显示，设定此对象为隐藏状态
        if ("block" == document.getElementById("error").style.display) {
          document.getElementById("error").style.display = "none";
        }
      }
    },

    //由于在Android平台上和在IOS平台上打开文件执行的不一样，所以在这边加上了具体的平台判断
    //IOS:调用照片库，返回文件
    //Android:调用自己写插件，通过自己写的插件，调用自己写的原生浏览文件的一个Activity浏览文件返回指定路径
    executeOpenFile() {
      console.log(" executeOpenFile()-->start");
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }

      this.resetloading();
      document.getElementById("contron").innerHTML = "开始";
      mam.navigator.dlfilebreakpointtransfer.pause(successCallback, null);

      function successCallback(msg) {}

      function errorCallback(msg) {}
      this.isstart = false;

      //打开文件时清除掉其中的内容
      document.getElementById("isok").innerHTML = "";
      //获取设备平台
      var devicePlatform = device.platform;
      console.log(" executeOpenFile() ,devicePlatform:" + devicePlatform);
      if ("iOS" == devicePlatform) {
        this.executeOpenFileByIOS();
      } else if ("Android" == devicePlatform) {
        this.executeOpenFileByAndroid();
      } else {
        console.log("invaiate platform");
      }
    },

    //为Android平台时打开文件执行的操作[自己写的插件，打开自己写的本地应用此应用显示系统文件信息，用户选择后带回文件信息]
    executeOpenFileByAndroid() {
      console.log("executeOpenFileByAndroid()-->start");
      mam.navigator.forward.goToFileExplorer(
        successCallback,
        null,
        DLForwardConstants.FileExplorer.ACTION_BREAK_POINT_FILE_UPLOAD
      );
      function successCallback(filePath) {
        console.log("successCallback() filePath:" + filePath);
        document.getElementById("file").value = filePath;
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    //为IOS平台时，执行打开文件时操作
    executeOpenFileByIOS() {
      console.log("executeOpenFileByIOS()-->start");
      mam.navigator.camera.getPicture(uploadPhoto, errorCallback, {
        quality: 50,
        destinationType: mam.navigator.camera.DestinationType.FILE_URI,
        sourceType: mam.navigator.camera.PictureSourceType.PHOTOLIBRARY,
      });
      function uploadPhoto(filePath) {
        console.log("successCallback() filePath:" + filePath);
        document.getElementById("file").value = filePath;
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },
    requireImg(url) {
      return require("@/assets/" + url);
    },
  },
};
</script>
<style lang='css' scoped>
/* @import url(); 引入css类 */
</style>